import React from 'react';
import { PlusSquare, Upload, Image as ImageIcon, Download } from 'lucide-react';

const Toolbar = ({ onAdd, onImport, onScan, onExport, isImporting, isOCRing }) => {
  return (
    <div style={{ display: 'flex', gap: '1rem', padding: '1.5rem 2rem 0.5rem', backgroundColor: '#fff' }}>
      
      <button className="btn btn-primary" onClick={onAdd}>
        <PlusSquare size={18} /> Thêm bài tập
      </button>

      <label className="btn" style={{ backgroundColor: '#f1f5f9', color: '#475569', cursor: isImporting ? 'not-allowed' : 'pointer', border: '1px solid #e2e8f0' }}>
        <input 
          type="file" 
          accept=".tex,.txt" 
          style={{ display: 'none' }} 
          onChange={onImport} 
          disabled={isImporting}
        />
        <Upload size={18} /> {isImporting ? 'Đang xử lý...' : 'Import .tex'}
      </label>

      <label className="btn" style={{ backgroundColor: '#fff7ed', color: '#c2410c', cursor: isOCRing ? 'not-allowed' : 'pointer', border: '1px solid #fed7aa' }}>
        <input 
          type="file" 
          accept="image/png, image/jpeg, application/pdf" 
          style={{ display: 'none' }} 
          onChange={onScan} 
          disabled={isOCRing}
        />
        <ImageIcon size={18} /> {isOCRing ? 'Đang đọc...' : 'Quét Ảnh/PDF'}
      </label>

      {/* Đẩy nút Xuất đề sang sát lề phải */}
      <div style={{ marginLeft: 'auto' }}>
        <button className="btn" style={{ backgroundColor: '#f0fdf4', color: '#16a34a', border: '1px solid #bbf7d0' }} onClick={onExport}>
          <Download size={18} /> Xuất Đề Thi
        </button>
      </div>

    </div>
  );
};

export default Toolbar;
